using ContosoUniversity.Data;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests
{
    public static class TestHelpers
    {
        public static SchoolContext CreateInMemoryContext()
        {
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName: Guid.NewGuid().ToString())
                .Options;
            return new SchoolContext(options);
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class NotificationServiceTests : IDisposable
    {
        private readonly NotificationService _service;

        public NotificationServiceTests()
        {
            _service = new NotificationService();
            // Drain any leftover notifications from the static queue
            while (_service.ReceiveNotification() != null) { }
        }

        public void Dispose()
        {
            // Drain queue after each test to avoid cross-test contamination
            while (_service.ReceiveNotification() != null) { }
            _service.Dispose();
        }

        [Fact]
        public void SendNotification_Create_EnqueuesNotification()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Student", notification.EntityType);
            Assert.Equal("1", notification.EntityId);
            Assert.Equal("CREATE", notification.Operation);
            Assert.False(notification.IsRead);
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_Update_EnqueuesNotification()
        {
            _service.SendNotification("Course", "42", EntityOperation.UPDATE, "admin");

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("Course", notification.EntityType);
            Assert.Equal("42", notification.EntityId);
            Assert.Equal("UPDATE", notification.Operation);
            Assert.Equal("admin", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_Delete_EnqueuesNotification()
        {
            _service.SendNotification("Department", "5", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Equal("DELETE", notification.Operation);
        }

        [Fact]
        public void SendNotification_WithEntityDisplayName_IncludesNameInMessage()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("John Doe", notification.Message);
            Assert.Contains("Student", notification.Message);
            Assert.Contains("created", notification.Message);
        }

        [Fact]
        public void SendNotification_WithoutEntityDisplayName_UsesIdInMessage()
        {
            _service.SendNotification("Student", "99", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains("ID: 99", notification.Message);
        }

        [Theory]
        [InlineData(EntityOperation.CREATE, "created")]
        [InlineData(EntityOperation.UPDATE, "updated")]
        [InlineData(EntityOperation.DELETE, "deleted")]
        public void SendNotification_OperationTypes_GenerateCorrectMessage(EntityOperation operation, string expectedWord)
        {
            _service.SendNotification("Entity", "1", "Test", operation);

            var notification = _service.ReceiveNotification();
            Assert.NotNull(notification);
            Assert.Contains(expectedWord, notification.Message);
        }

        [Fact]
        public void SendNotification_CreateWithDisplayName_MessageFormat()
        {
            _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student 'John Doe' has been created", notification.Message);
        }

        [Fact]
        public void SendNotification_UpdateWithDisplayName_MessageFormat()
        {
            _service.SendNotification("Course", "2", "Math 101", EntityOperation.UPDATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Course 'Math 101' has been updated", notification.Message);
        }

        [Fact]
        public void SendNotification_DeleteWithDisplayName_MessageFormat()
        {
            _service.SendNotification("Department", "3", "Engineering", EntityOperation.DELETE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("Department 'Engineering' has been deleted", notification.Message);
        }

        [Fact]
        public void SendNotification_CreateWithoutDisplayName_MessageFormat()
        {
            _service.SendNotification("Student", "42", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.Equal("New Student (ID: 42) has been created", notification.Message);
        }

        [Fact]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            var notification = _service.ReceiveNotification();
            Assert.Null(notification);
        }

        [Fact]
        public void ReceiveNotification_DequeuesInOrder()
        {
            _service.SendNotification("A", "1", EntityOperation.CREATE);
            _service.SendNotification("B", "2", EntityOperation.UPDATE);

            var first = _service.ReceiveNotification();
            var second = _service.ReceiveNotification();

            Assert.Equal("A", first.EntityType);
            Assert.Equal("B", second.EntityType);
        }

        [Fact]
        public void ReceiveNotification_AfterDequeue_QueueIsEmpty()
        {
            _service.SendNotification("X", "1", EntityOperation.CREATE);
            _service.ReceiveNotification();

            Assert.Null(_service.ReceiveNotification());
        }

        [Fact]
        public void MarkAsRead_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(1));
            Assert.Null(exception);
        }

        [Fact]
        public void MarkAsRead_WithAnyId_DoesNotThrow()
        {
            var exception = Record.Exception(() => _service.MarkAsRead(999));
            Assert.Null(exception);
        }

        [Fact]
        public void QueueCap_ExceedingMaxLength_OldestRemoved()
        {
            // Send 505 notifications to exceed the 500 cap
            for (int i = 0; i < 505; i++)
            {
                _service.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
            }

            // The queue should have at most 500 items
            int count = 0;
            while (_service.ReceiveNotification() != null)
            {
                count++;
            }
            Assert.True(count <= 500);
        }

        [Fact]
        public void Dispose_DoesNotThrow()
        {
            var service = new NotificationService();
            var exception = Record.Exception(() => service.Dispose());
            Assert.Null(exception);
        }

        [Fact]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE, null);

            var notification = _service.ReceiveNotification();
            Assert.Equal("System", notification.CreatedBy);
        }

        [Fact]
        public void SendNotification_SetsCreatedAt()
        {
            var before = DateTime.Now;
            _service.SendNotification("Student", "1", EntityOperation.CREATE);
            var after = DateTime.Now;

            var notification = _service.ReceiveNotification();
            Assert.InRange(notification.CreatedAt, before, after);
        }

        [Fact]
        public void SendNotification_SetsIsReadToFalse()
        {
            _service.SendNotification("Student", "1", EntityOperation.CREATE);

            var notification = _service.ReceiveNotification();
            Assert.False(notification.IsRead);
        }
    }
}

using Xunit;

namespace ContosoUniversity.Tests
{
    public class PaginatedListTests
    {
        [Fact]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void Create_SecondPage_ReturnsCorrectItems()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.Equal(5, result.Count);
            Assert.Equal(2, result.PageIndex);
            Assert.Equal(new[] { 6, 7, 8, 9, 10 }, result.ToArray());
        }

        [Fact]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            var source = Enumerable.Range(1, 12).AsQueryable();

            var result = PaginatedList<int>.Create(source, 3, 5);

            Assert.Equal(2, result.Count);
            Assert.Equal(3, result.PageIndex);
        }

        [Fact]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Empty(result);
            Assert.Equal(1, result.PageIndex);
            Assert.Equal(0, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_OnFirstPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasPreviousPage_OnSecondPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 2, 5);

            Assert.True(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_OnLastPage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 4, 5);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_OnFirstPage_ReturnsTrue()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.True(result.HasNextPage);
        }

        [Fact]
        public void TotalPages_ExactDivision_CalculatesCorrectly()
        {
            var source = Enumerable.Range(1, 20).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(4, result.TotalPages);
        }

        [Fact]
        public void TotalPages_NonExactDivision_RoundsUp()
        {
            var source = Enumerable.Range(1, 11).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(3, result.TotalPages);
        }

        [Fact]
        public void TotalPages_SingleItem_ReturnsOne()
        {
            var source = new[] { 1 }.AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.Equal(1, result.TotalPages);
        }

        [Theory]
        [InlineData(10, 3, 4)]
        [InlineData(1, 1, 1)]
        [InlineData(100, 10, 10)]
        [InlineData(7, 3, 3)]
        public void TotalPages_Various_CalculatesCorrectly(int itemCount, int pageSize, int expectedPages)
        {
            var source = Enumerable.Range(1, itemCount).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, pageSize);

            Assert.Equal(expectedPages, result.TotalPages);
        }

        [Fact]
        public void HasPreviousPage_EmptySource_ReturnsFalse()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.False(result.HasPreviousPage);
        }

        [Fact]
        public void HasNextPage_EmptySource_ReturnsFalse()
        {
            var source = Enumerable.Empty<int>().AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.False(result.HasNextPage);
        }

        [Fact]
        public void HasNextPage_SinglePage_ReturnsFalse()
        {
            var source = Enumerable.Range(1, 3).AsQueryable();

            var result = PaginatedList<int>.Create(source, 1, 5);

            Assert.False(result.HasNextPage);
        }
    }
}

