using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class StudentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly StudentsController _controller;

        public StudentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new StudentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private void SeedStudents()
        {
            _context.Students.AddRange(
                new Student { FirstMidName = "Alice", LastName = "Anderson", EnrollmentDate = new DateTime(2020, 9, 1) },
                new Student { FirstMidName = "Bob", LastName = "Brown", EnrollmentDate = new DateTime(2021, 9, 1) },
                new Student { FirstMidName = "Charlie", LastName = "Clark", EnrollmentDate = new DateTime(2019, 9, 1) }
            );
            _context.SaveChanges();
        }

        // Index Tests
        [Fact]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            SeedStudents();

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Anderson", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Clark", model[2].LastName);
        }

        [Fact]
        public void Index_NameDesc_OrdersByLastNameDescending()
        {
            SeedStudents();

            var result = _controller.Index("name_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Clark", model[0].LastName);
            Assert.Equal("Brown", model[1].LastName);
            Assert.Equal("Anderson", model[2].LastName);
        }

        [Fact]
        public void Index_DateSort_OrdersByEnrollmentDateAscending()
        {
            SeedStudents();

            var result = _controller.Index("Date", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Clark", model[0].LastName); // 2019
            Assert.Equal("Anderson", model[1].LastName); // 2020
            Assert.Equal("Brown", model[2].LastName); // 2021
        }

        [Fact]
        public void Index_DateDesc_OrdersByEnrollmentDateDescending()
        {
            SeedStudents();

            var result = _controller.Index("date_desc", null, null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal("Brown", model[0].LastName); // 2021
        }

        [Fact]
        public void Index_SearchString_FiltersStudents()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Alice", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Alice", model[0].FirstMidName);
        }

        [Fact]
        public void Index_SearchByLastName_FiltersStudents()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Brown", null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
            Assert.Equal("Brown", model[0].LastName);
        }

        [Fact]
        public void Index_SearchString_SetsPageTo1()
        {
            SeedStudents();

            var result = _controller.Index(null, null, "Alice", 3) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(1, model.PageIndex);
        }

        [Fact]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            SeedStudents();

            var result = _controller.Index(null, "Alice", null, null) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_SetsViewBagProperties()
        {
            SeedStudents();

            var result = _controller.Index(null, null, null, null) as ViewResult;

            Assert.Null(_controller.ViewBag.CurrentSort);
            Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
            Assert.Equal("Date", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_WithSortOrder_SetsCorrectSortParms()
        {
            SeedStudents();

            _controller.Index("Date", null, null, null);

            Assert.Equal("", _controller.ViewBag.NameSortParm);
            Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        }

        [Fact]
        public void Index_Pagination_ReturnsCorrectPage()
        {
            // Add more than 10 students for pagination
            for (int i = 0; i < 15; i++)
            {
                _context.Students.Add(new Student
                {
                    FirstMidName = $"Student{i}",
                    LastName = $"Last{i:D2}",
                    EnrollmentDate = DateTime.Today
                });
            }
            _context.SaveChanges();

            var result = _controller.Index(null, null, null, 2) as ViewResult;

            var model = Assert.IsType<PaginatedList<Student>>(result.Model);
            Assert.Equal(2, model.PageIndex);
            Assert.Equal(5, model.Count); // 15 - 10 = 5 on page 2
        }

        // Details Tests
        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsStudent()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Details(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        // Create GET Tests
        [Fact]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(DateTime.Today, model.EnrollmentDate);
        }

        // Create POST Tests
        [Fact]
        public void Create_Post_ValidStudent_SavesAndRedirects()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Students);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.Equal(student, result.Model);
        }

        [Fact]
        public void Create_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        [Fact]
        public void Create_Post_OutOfRangeDate_AddsModelError()
        {
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1000, 1, 1)
            };

            var result = _controller.Create(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        // Edit GET Tests
        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsStudent()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Edit(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(999);

            Assert.IsType<NotFoundResult>(result);
        }

        // Edit POST Tests
        [Fact]
        public void Edit_Post_ValidStudent_SavesAndRedirects()
        {
            SeedStudents();
            var student = _context.Students.First();
            // Detach to avoid tracking conflicts
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedStudent = new Student
            {
                ID = student.ID,
                FirstMidName = "Updated",
                LastName = "Name",
                EnrollmentDate = new DateTime(2023, 1, 1)
            };

            var result = _controller.Edit(editedStudent) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
        }

        [Fact]
        public void Edit_Post_MinValueDate_AddsModelError()
        {
            var student = new Student
            {
                ID = 1,
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            var result = _controller.Edit(student) as ViewResult;

            Assert.NotNull(result);
            Assert.False(_controller.ModelState.IsValid);
        }

        // Delete GET Tests
        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsStudent()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.Delete(student.ID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Student>(result.Model);
            Assert.Equal(student.ID, model.ID);
        }

        [Fact]
        public void Delete_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Delete(999);

            Assert.IsType<NotFoundResult>(result);
        }

        // DeleteConfirmed Tests
        [Fact]
        public void DeleteConfirmed_ValidId_DeletesAndRedirects()
        {
            SeedStudents();
            var student = _context.Students.First();

            var result = _controller.DeleteConfirmed(student.ID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Equal(2, _context.Students.Count());
        }

        [Fact]
        public void DeleteConfirmed_InvalidId_RedirectsWithError()
        {
            var result = _controller.DeleteConfirmed(999) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Microsoft.Extensions.Logging;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class CoursesControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly CoursesController _controller;
        private readonly Mock<IWebHostEnvironment> _envMock;
        private readonly Mock<ILogger<CoursesController>> _loggerMock;

        public CoursesControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _envMock = new Mock<IWebHostEnvironment>();
            _envMock.Setup(e => e.WebRootPath).Returns((string)null);
            _envMock.Setup(e => e.ContentRootPath).Returns(Directory.GetCurrentDirectory());
            _loggerMock = new Mock<ILogger<CoursesController>>();
            _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Department SeedDepartment()
        {
            var dept = new Department
            {
                Name = "Engineering",
                Budget = 100000,
                StartDate = new DateTime(2020, 1, 1)
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        private Course SeedCourse(Department dept = null)
        {
            dept ??= SeedDepartment();
            var course = new Course
            {
                CourseID = 1001,
                Title = "Test Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };
            _context.Courses.Add(course);
            _context.SaveChanges();
            return course;
        }

        // Index Tests
        [Fact]
        public void Index_ReturnsCoursesWithDepartments()
        {
            var dept = SeedDepartment();
            SeedCourse(dept);

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<List<Course>>(result.Model);
            Assert.Empty(model);
        }

        // Details Tests
        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsCourse()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(dept);

            var result = _controller.Details(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        // Create GET Tests
        [Fact]
        public void Create_Get_PopulatesDepartmentViewBag()
        {
            SeedDepartment();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Get_ReturnsNewCourse()
        {
            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.IsType<Course>(result.Model);
        }

        // Create POST Tests
        [Fact]
        public void Create_Post_ValidCourse_SavesAndRedirects()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "New Course",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Courses);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            var dept = SeedDepartment();
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course
            {
                CourseID = 2001,
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Create(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Create_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.txt");
            fileMock.Setup(f => f.Length).Returns(100);

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        [Fact]
        public void Create_Post_FileTooLarge_ReturnsViewWithError()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 2001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("test.jpg");
            fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

            var result = _controller.Create(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // Edit GET Tests
        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsCourseWithViewBag()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(dept);

            var result = _controller.Edit(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Get_NotFound_ReturnsNotFound()
        {
            var result = _controller.Edit(9999);

            Assert.IsType<NotFoundResult>(result);
        }

        // Edit POST Tests
        [Fact]
        public void Edit_Post_ValidCourse_SavesAndRedirects()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(dept);
            _context.Entry(course).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var editedCourse = new Course
            {
                CourseID = course.CourseID,
                Title = "Updated Course",
                Credits = 4,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Edit(editedCourse, null) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
        }

        [Fact]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            var dept = SeedDepartment();
            _controller.ModelState.AddModelError("Title", "Required");
            var course = new Course
            {
                CourseID = 1001,
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var result = _controller.Edit(course, null) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.DepartmentID);
        }

        [Fact]
        public void Edit_Post_InvalidFileExtension_ReturnsViewWithError()
        {
            var dept = SeedDepartment();
            var course = new Course
            {
                CourseID = 1001,
                Title = "Test",
                Credits = 3,
                DepartmentID = dept.DepartmentID
            };

            var fileMock = new Mock<IFormFile>();
            fileMock.Setup(f => f.FileName).Returns("doc.pdf");
            fileMock.Setup(f => f.Length).Returns(100);

            var result = _controller.Edit(course, fileMock.Object) as ViewResult;

            Assert.NotNull(result);
            Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
        }

        // Delete GET Tests
        [Fact]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Delete(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Delete_Get_ValidId_ReturnsCourse()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(dept);

            var result = _controller.Delete(course.CourseID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Course>(result.Model);
            Assert.Equal(course.CourseID, model.CourseID);
        }

        // DeleteConfirmed Tests
        [Fact]
        public void DeleteConfirmed_ValidId_DeletesAndRedirects()
        {
            var dept = SeedDepartment();
            var course = SeedCourse(dept);

            var result = _controller.DeleteConfirmed(course.CourseID) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Empty(_context.Courses);
        }
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.ViewFeatures;
using Moq;
using Xunit;

namespace ContosoUniversity.Tests
{
    public class DepartmentsControllerTests : IDisposable
    {
        private readonly SchoolContext _context;
        private readonly DepartmentsController _controller;

        public DepartmentsControllerTests()
        {
            _context = TestHelpers.CreateInMemoryContext();
            _controller = new DepartmentsController(_context);
            _controller.ControllerContext = new ControllerContext
            {
                HttpContext = new DefaultHttpContext()
            };
            _controller.TempData = new TempDataDictionary(
                new DefaultHttpContext(),
                Mock.Of<ITempDataProvider>());
        }

        public void Dispose()
        {
            _controller.Dispose();
            _context.Dispose();
        }

        private Instructor SeedInstructor()
        {
            var instructor = new Instructor
            {
                FirstMidName = "John",
                LastName = "Doe",
                HireDate = new DateTime(2010, 1, 1)
            };
            _context.Instructors.Add(instructor);
            _context.SaveChanges();
            return instructor;
        }

        private Department SeedDepartment(Instructor instructor = null)
        {
            instructor ??= SeedInstructor();
            var dept = new Department
            {
                Name = "Computer Science",
                Budget = 200000,
                StartDate = new DateTime(2020, 1, 1),
                InstructorID = instructor.ID
            };
            _context.Departments.Add(dept);
            _context.SaveChanges();
            return dept;
        }

        // Index Tests
        [Fact]
        public void Index_ReturnsDepartmentsWithAdministrator()
        {
            SeedDepartment();

            var result = _controller.Index() as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Single(model);
        }

        [Fact]
        public void Index_EmptyDatabase_ReturnsEmptyList()
        {
            var result = _controller.Index() as ViewResult;

            var model = Assert.IsAssignableFrom<List<Department>>(result.Model);
            Assert.Empty(model);
        }

        // Details Tests
        [Fact]
        public void Details_NullId_ReturnsBadRequest()
        {
            var result = _controller.Details(null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Details_ValidId_ReturnsDepartment()
        {
            var dept = SeedDepartment();

            var result = _controller.Details(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
            var model = Assert.IsType<Department>(result.Model);
            Assert.Equal(dept.DepartmentID, model.DepartmentID);
        }

        [Fact]
        public void Details_NotFound_ReturnsNotFound()
        {
            var result = _controller.Details(999);

            Assert.IsType<NotFoundResult>(result);
        }

        // Create GET Tests
        [Fact]
        public void Create_Get_PopulatesInstructorViewBag()
        {
            SeedInstructor();

            var result = _controller.Create() as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // Create POST Tests
        [Fact]
        public void Create_Post_ValidDepartment_SavesAndRedirects()
        {
            var instructor = SeedInstructor();
            var dept = new Department
            {
                Name = "Mathematics",
                Budget = 150000,
                StartDate = new DateTime(2021, 1, 1),
                InstructorID = instructor.ID
            };

            var result = _controller.Create(dept) as RedirectToActionResult;

            Assert.NotNull(result);
            Assert.Equal("Index", result.ActionName);
            Assert.Single(_context.Departments);
        }

        [Fact]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            _controller.ModelState.AddModelError("Name", "Required");
            var dept = new Department
            {
                Budget = 150000,
                StartDate = new DateTime(2021, 1, 1)
            };

            var result = _controller.Create(dept) as ViewResult;

            Assert.NotNull(result);
            Assert.NotNull(_controller.ViewBag.InstructorID);
        }

        // Edit GET Tests
        [Fact]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            var result = _controller.Edit((int?)null);

            var statusResult = Assert.IsType<StatusCodeResult>(result);
            Assert.Equal(400, statusResult.StatusCode);
        }

        [Fact]
        public void Edit_Get_ValidId_ReturnsDepartmentWithViewBag()
        {
            var instructor = SeedInstructor();
            var dept = SeedDepartment(instructor);

            var result = _controller.Edit(dept.DepartmentID) as ViewResult;

            Assert.NotNull(result);
