        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
            Assert.Equal(5, context.Instructors.Count());
            Assert.Equal(4, context.Departments.Count());
            Assert.Equal(7, context.Courses.Count());
            Assert.Equal(3, context.OfficeAssignments.Count());
            Assert.Equal(8, context.CourseAssignments.Count());
            Assert.True(context.Enrollments.Count() > 0);
        }

        [Fact]
        public void Initialize_ExistingStudents_SkipsSeeding()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            // Pre-seed with a student
            context.Students.Add(new Student
            {
                FirstMidName = "Existing",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 1, 1)
            });
            context.SaveChanges();

            DbInitializer.Initialize(context);

            // Should only have the one student we added
            Assert.Single(context.Students);
            Assert.Empty(context.Departments);
        }

        [Fact]
        public void Initialize_CalledTwice_DoesNotDuplicate()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);
            DbInitializer.Initialize(context);

            Assert.Equal(8, context.Students.Count());
        }

        [Fact]
        public void Initialize_SeedsCorrectStudentNames()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var lastNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
            Assert.Contains("Alexander", lastNames);
            Assert.Contains("Alonso", lastNames);
            Assert.Contains("Olivetto", lastNames);
        }

        [Fact]
        public void Initialize_SeedsCorrectDepartmentNames()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var names = context.Departments.Select(d => d.Name).ToList();
            Assert.Contains("English", names);
            Assert.Contains("Mathematics", names);
            Assert.Contains("Engineering", names);
            Assert.Contains("Economics", names);
        }

        [Fact]
        public void Initialize_SeedsCourseAssignments()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            Assert.Equal(8, context.CourseAssignments.Count());
        }

        [Fact]
        public void Initialize_SeedsEnrollmentsWithGrades()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var enrollments = context.Enrollments.ToList();
            Assert.True(enrollments.Count >= 10);
            Assert.Contains(enrollments, e => e.Grade == Grade.A);
            Assert.Contains(enrollments, e => e.Grade == Grade.B);
            Assert.Contains(enrollments, e => e.Grade == null);
        }

        [Fact]
        public void Initialize_SeedsOfficeAssignments()
        {
            using var context = TestHelpers.CreateInMemoryContext();

            DbInitializer.Initialize(context);

            var offices = context.OfficeAssignments.ToList();
            Assert.Equal(3, offices.Count);
            Assert.Contains(offices, o => o.Location == "Smith 17");
            Assert.Contains(offices, o => o.Location == "Gowan 27");
            Assert.Contains(offices, o => o.Location == "Thompson 304");
        }
    }
