+using ContosoUniversity.Controllers;
+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using ContosoUniversity.Services;
+using Microsoft.AspNetCore.Http;
+using Microsoft.AspNetCore.Mvc;
+using Microsoft.AspNetCore.Mvc.ViewFeatures;
+using Moq;
+using Xunit;
+
+namespace ContosoUniversity.Tests
+{
+    public class NotificationsControllerTests : IDisposable
+    {
+        private readonly SchoolContext _context;
+        private readonly NotificationsController _controller;
+
+        public NotificationsControllerTests()
+        {
+            _context = TestHelpers.CreateInMemoryContext();
+            _controller = new NotificationsController(_context);
+            _controller.ControllerContext = new ControllerContext
+            {
+                HttpContext = new DefaultHttpContext()
+            };
+            _controller.TempData = new TempDataDictionary(
+                new DefaultHttpContext(),
+                Mock.Of<ITempDataProvider>());
+
+            // Drain any leftover notifications
+            var svc = new NotificationService();
+            while (svc.ReceiveNotification() != null) { }
+        }
+
+        public void Dispose()
+        {
+            // Drain queue
+            var svc = new NotificationService();
+            while (svc.ReceiveNotification() != null) { }
+            _controller.Dispose();
+            _context.Dispose();
+        }
+
+        [Fact]
+        public void GetNotifications_EmptyQueue_ReturnsEmptyNotifications()
+        {
+            var result = _controller.GetNotifications();
+
+            Assert.NotNull(result);
+            var value = result.Value;
+            Assert.NotNull(value);
+            // Verify it's a success response with zero count
+            var successProp = value.GetType().GetProperty("success");
+            Assert.True((bool)successProp.GetValue(value));
+            var countProp = value.GetType().GetProperty("count");
+            Assert.Equal(0, (int)countProp.GetValue(value));
+        }
+
+        [Fact]
+        public void GetNotifications_WithNotifications_ReturnsNotifications()
+        {
+            var svc = new NotificationService();
+            svc.SendNotification("Student", "1", "Test Student", EntityOperation.CREATE);
+            svc.SendNotification("Course", "2", "Test Course", EntityOperation.UPDATE);
+
+            var result = _controller.GetNotifications();
+
+            var value = result.Value;
+            var countProp = value.GetType().GetProperty("count");
+            Assert.Equal(2, (int)countProp.GetValue(value));
+        }
+
+        [Fact]
+        public void GetNotifications_LimitsTo10()
+        {
+            var svc = new NotificationService();
+            for (int i = 0; i < 15; i++)
+            {
+                svc.SendNotification("Entity", i.ToString(), EntityOperation.CREATE);
+            }
+
+            var result = _controller.GetNotifications();
+
+            var value = result.Value;
+            var countProp = value.GetType().GetProperty("count");
+            Assert.Equal(10, (int)countProp.GetValue(value));
+        }
+
+        [Fact]
+        public void MarkAsRead_ReturnsSuccess()
+        {
+            var result = _controller.MarkAsRead(1);
+
+            var value = result.Value;
+            var successProp = value.GetType().GetProperty("success");
+            Assert.True((bool)successProp.GetValue(value));
+        }
+
+        [Fact]
+        public void Index_ReturnsView()
+        {
+            var result = _controller.Index() as ViewResult;
+
+            Assert.NotNull(result);
+        }
+    }
+}
