+using ContosoUniversity.Controllers;
+using ContosoUniversity.Data;
+using ContosoUniversity.Models;
+using Microsoft.AspNetCore.Http;
+using Microsoft.AspNetCore.Mvc;
+using Microsoft.AspNetCore.Mvc.ViewFeatures;
+using Moq;
+using Xunit;
+
+namespace ContosoUniversity.Tests
+{
+    // Concrete subclass to test BaseController
+    public class TestableController : BaseController
+    {
+        public TestableController(SchoolContext context) : base(context)
+        {
+        }
+
+        public void CallSendEntityNotification(string entityType, string entityId, EntityOperation operation)
+        {
+            SendEntityNotification(entityType, entityId, operation);
+        }
+
+        public void CallSendEntityNotification(string entityType, string entityId, string displayName, EntityOperation operation)
+        {
+            SendEntityNotification(entityType, entityId, displayName, operation);
+        }
+
+        public SchoolContext GetDb() => db;
+    }
+
+    public class BaseControllerTests : IDisposable
+    {
+        private readonly SchoolContext _context;
+        private readonly TestableController _controller;
+
+        public BaseControllerTests()
+        {
+            _context = TestHelpers.CreateInMemoryContext();
+            _controller = new TestableController(_context);
+            _controller.ControllerContext = new ControllerContext
+            {
+                HttpContext = new DefaultHttpContext()
+            };
+        }
+
+        public void Dispose()
+        {
+            _controller.Dispose();
+            _context.Dispose();
+        }
+
+        [Fact]
+        public void SendEntityNotification_WithoutDisplayName_DoesNotThrow()
+        {
+            var exception = Record.Exception(() =>
+                _controller.CallSendEntityNotification("Student", "1", EntityOperation.CREATE));
+
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void SendEntityNotification_WithDisplayName_DoesNotThrow()
+        {
+            var exception = Record.Exception(() =>
+                _controller.CallSendEntityNotification("Student", "1", "John Doe", EntityOperation.CREATE));
+
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void SendEntityNotification_AllOperations_DoNotThrow()
+        {
+            var exception = Record.Exception(() =>
+            {
+                _controller.CallSendEntityNotification("A", "1", EntityOperation.CREATE);
+                _controller.CallSendEntityNotification("B", "2", EntityOperation.UPDATE);
+                _controller.CallSendEntityNotification("C", "3", EntityOperation.DELETE);
+            });
+
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void Dispose_DoesNotThrow()
+        {
+            var context = TestHelpers.CreateInMemoryContext();
+            var controller = new TestableController(context);
+
+            var exception = Record.Exception(() => controller.Dispose());
+
+            Assert.Null(exception);
+        }
+
+        [Fact]
+        public void Constructor_SetsDbContext()
+        {
+            Assert.NotNull(_controller.GetDb());
+            Assert.Same(_context, _controller.GetDb());
+        }
+    }
+}
